import { ref, computed } from 'vue'
import { useRouter } from 'vue-router'
import { auth } from '@/api/auth'
import { SMS_SCENE } from '@/constants'
import { showToast } from '@/components/ToastMessage'

export function useResetPassword() {
  const router = useRouter()

  // 表单数据
  const form = ref({
    phone: '',
    code: '',
    password: '',
    confirmPassword: ''
  })

  // 状态
  const loading = ref(false)
  const countdown = ref(0)
  const showPassword = ref(false)

  // 表单验证
  const isFormValid = computed(() => {
    return form.value.phone && 
           form.value.code && 
           form.value.password &&
           form.value.confirmPassword &&
           form.value.password === form.value.confirmPassword &&
           form.value.password.length >= 6 &&
           /^1[3-9]\d{9}$/.test(form.value.phone)
  })

  // 验证函数
  const validatePhone = () => {
    const phoneRegex = /^1[3-9]\d{9}$/
    if (!form.value.phone) {
      showToast('请输入手机号', 'warning')
      return false
    }
    if (!phoneRegex.test(form.value.phone)) {
      showToast('请输入正确的手机号', 'warning')
      return false
    }
    return true
  }

  const validatePassword = () => {
    if (!form.value.password) {
      showToast('请输入新密码', 'warning')
      return false
    }
    if (form.value.password.length < 6) {
      showToast('密码长度不能少于6位', 'warning')
      return false
    }
    return true
  }

  const validateConfirmPassword = () => {
    if (!form.value.confirmPassword) {
      showToast('请确认密码', 'warning')
      return false
    }
    if (form.value.confirmPassword !== form.value.password) {
      showToast('两次输入的密码不一致', 'warning')
      return false
    }
    return true
  }

  // 发送验证码
  const handleSendCode = async () => {
    if (!validatePhone()) return

    try {
      loading.value = true
      const params = {
        phone: form.value.phone,
        scene: SMS_SCENE.RESET_PASSWORD
      }
      console.log('发送验证码请求参数:', params)

      console.log('开始发送验证码请求...')
      const response = await auth.sendVerifyCode(params)
      console.log('验证码请求完成，响应:', response)

      if (response.data?.code === 200) {
        console.log('验证码发送成功:', {
          responseData: response.data,
          phone: form.value.phone,
          scene: SMS_SCENE.RESET_PASSWORD
        })

        showToast('验证码已发送', 'success')
        countdown.value = 60
        const timer = setInterval(() => {
          countdown.value--
          if (countdown.value <= 0) {
            clearInterval(timer)
          }
        }, 1000)
      } else {
        console.warn('验证码发送响应异常:', response.data)
        throw new Error(response.data?.message || '发送验证码失败')
      }
    } catch (error) {
      console.error('发送验证码失败:', {
        error,
        response: error.response,
        data: error.response?.data,
        status: error.response?.status,
        message: error.message
      })

      if (error.response?.data?.message?.includes('未注册')) {
        showToast('该手机号未注册，请先注册', 'warning')
        setTimeout(() => {
          router.push('/register')
        }, 1500)
        return
      }

      const errorMessage = error.response?.data?.message || 
                          error.response?.data?.detail || 
                          error.message || 
                          '发送验证码失败，请重试'
      showToast(errorMessage, 'error')
    } finally {
      loading.value = false
    }
  }

  // 重置密码
  const handleResetPassword = async () => {
    if (!validatePhone()) return
    if (!form.value.code) {
      showToast('请输入验证码', 'warning')
      return
    }
    if (!validatePassword()) return
    if (!validateConfirmPassword()) return

    try {
      loading.value = true
      const resetData = {
        phone: form.value.phone,
        code: form.value.code,
        new_password: form.value.password,
        confirm_password: form.value.confirmPassword
      }
      console.log('重置密码请求参数:', resetData)

      const response = await auth.resetPassword(resetData)
      console.log('重置密码响应:', response)

      if (response.data?.code === 200 || response.data?.detail === '密码重置成功') {
        showToast('密码重置成功', 'success')
        setTimeout(() => {
          router.push('/login')
        }, 1500)
      } else {
        throw new Error(response.data?.message || response.data?.detail || '重置密码失败，请重试')
      }
    } catch (error) {
      console.error('重置密码失败:', error.response || error)
      const errorMessage = error.response?.data?.message || 
                          error.response?.data?.detail || 
                          error.message || 
                          '重置密码失败，请重试'
      showToast(errorMessage, 'error')
    } finally {
      loading.value = false
    }
  }

  // 切换密码显示
  const togglePassword = () => {
    showPassword.value = !showPassword.value
  }

  return {
    form,
    loading,
    countdown,
    showPassword,
    isFormValid,
    handleSendCode,
    handleResetPassword,
    togglePassword
  }
}
